     1→/**
     2→ * ConvergioEdu Character Router
     3→ *
     4→ * Routes students to the appropriate character based on:
     5→ * 1. Detected intent (academic, method, emotional)
     6→ * 2. Student preferences (preferred coach/buddy gender)
     7→ * 3. Subject matter (for Maestro selection)
     8→ *
     9→ * This is the orchestration layer of the Support Triangle.
    10→ * Related: #24 MirrorBuddy Issue, ManifestoEdu.md
    11→ */
    12→
    13→import type {
    14→  Subject,
    15→  CharacterType,
    16→  SupportTeacher,
    17→  BuddyProfile,
    18→  ExtendedStudentProfile,
    19→  SupportCharacter,
    20→} from '@/types';
    21→import type { MaestroFull } from '@/data/maestri';
    22→import { getMaestroById, getMaestriBySubject } from '@/data/maestri';
    23→import {
    24→  getSupportTeacherById,
    25→  getDefaultSupportTeacher,
    26→} from '@/data/support-teachers';
    27→import {
    28→  getBuddyById,
    29→  getDefaultBuddy,
    30→  type BuddyId,
    31→} from '@/data/buddy-profiles';
    32→import { detectIntent, type DetectedIntent } from './intent-detection';
    33→import { injectSafetyGuardrails } from '@/lib/safety';
    34→
    35→// ============================================================================
    36→// TYPES
    37→// ============================================================================
    38→
    39→/**
    40→ * Result of character routing.
    41→ */
    42→export interface RoutingResult {
    43→  /** The character type selected */
    44→  characterType: CharacterType;
    45→  /** The specific character to use */
    46→  character: MaestroFull | SupportTeacher | BuddyProfile;
    47→  /** The intent that led to this routing */
    48→  intent: DetectedIntent;
    49→  /** Why this character was selected */
    50→  reason: string;
    51→  /** Alternative characters that could also help */
    52→  alternatives?: Array<{
    53→    character: MaestroFull | SupportTeacher | BuddyProfile;
    54→    reason: string;
    55→  }>;
    56→}
    57→
    58→/**
    59→ * Student context for routing decisions.
    60→ */
    61→export interface RoutingContext {
    62→  /** The student's message to route */
    63→  message: string;
    64→  /** The student's profile with preferences */
    65→  studentProfile: ExtendedStudentProfile;
    66→  /** Currently active character (for conversation continuity) */
    67→  currentCharacter?: {
    68→    type: CharacterType;
    69→    id: string;
    70→  };
    71→  /** Whether to prefer continuity over optimal routing */
    72→  preferContinuity?: boolean;
    73→}
    74→
    75→// ============================================================================
    76→// SUBJECT TO MAESTRO MAPPING
    77→// ============================================================================
    78→
    79→/**
    80→ * Default Maestro IDs for each subject.
    81→ * These are the "primary" Maestri for each subject.
    82→ */
    83→const DEFAULT_MAESTRO_BY_SUBJECT: Record<Subject, string> = {
    84→  mathematics: 'euclide-matematica',
    85→  physics: 'feynman-fisica',
    86→  chemistry: 'curie-chimica',
    87→  biology: 'darwin-biologia', // Fallback will find actual maestro if exists
    88→  history: 'erodoto-storia',
    89→  geography: 'humboldt-geografia',
    90→  italian: 'manzoni-italiano',
    91→  english: 'shakespeare-inglese',
    92→  art: 'leonardo-arte',
    93→  music: 'mozart-musica',
    94→  civics: 'montessori-civica', // Fallback will find actual maestro if exists
    95→  economics: 'smith-economia',
    96→  computerScience: 'turing-informatica', // Fallback will find actual maestro if exists
    97→  health: 'ippocrate-salute', // Fallback will find actual maestro if exists
    98→  philosophy: 'socrate-filosofia',
    99→  internationalLaw: 'grozio-diritto', // Fallback will find actual maestro if exists
   100→};
   101→
   102→// ============================================================================
   103→// ROUTING FUNCTIONS
   104→// ============================================================================
   105→
   106→/**
   107→ * Gets the appropriate Maestro for a subject.
   108→ */
   109→function getMaestroForSubject(subject: Subject): MaestroFull | undefined {
   110→  const defaultId = DEFAULT_MAESTRO_BY_SUBJECT[subject];
   111→  if (defaultId) {
   112→    const maestro = getMaestroById(defaultId);
   113→    if (maestro) return maestro;
   114→  }
   115→
   116→  // Fallback: get first Maestro for this subject
   117→  const maestri = getMaestriBySubject(subject);
   118→  return maestri[0];
   119→}
   120→
   121→/**
   122→ * Gets the appropriate Coach based on student preferences.
   123→ */
   124→function getCoachForStudent(profile: ExtendedStudentProfile): SupportTeacher {
   125→  if (profile.preferredCoach) {
   126→    const preferred = getSupportTeacherById(profile.preferredCoach);
   127→    if (preferred) {
   128→      return preferred;
   129→    }
   130→  }
   131→
   132→  // No preference: use default (Melissa)
   133→  return getDefaultSupportTeacher();
   134→}
   135→
   136→/**
   137→ * Gets the appropriate Buddy based on student preferences.
   138→ */
   139→export function getBuddyForStudent(profile: ExtendedStudentProfile): BuddyProfile {
   140→  if (profile.preferredBuddy) {
   141→    const preferred = getBuddyById(profile.preferredBuddy);
   142→    if (preferred) {
   143→      return preferred;
   144→    }
   145→  }
   146→
   147→  // No preference: use default (Mario)
   148→  return getDefaultBuddy();
   149→}
   150→
   151→/**
   152→ * Main routing function.
   153→ * Analyzes the message and routes to the best character.
   154→ *
   155→ * @param context - The routing context with message and student profile
   156→ * @returns Routing result with selected character and reasoning
   157→ *
   158→ * @example
   159→ * const result = routeToCharacter({
   160→ *   message: "Non capisco le equazioni di secondo grado",
   161→ *   studentProfile: { age: 14, learningDifferences: ['adhd'] },
   162→ * });
   163→ * // Returns: { characterType: 'maestro', character: euclide, ... }
   164→ */
   165→export function routeToCharacter(context: RoutingContext): RoutingResult {
   166→  const { message, studentProfile, currentCharacter, preferContinuity } = context;
   167→
   168→  // 1. Detect intent
   169→  const intent = detectIntent(message);
   170→
   171→  // 2. Check for continuity preference
   172→  if (preferContinuity && currentCharacter) {
   173→    // If confidence is not very high, stay with current character
   174→    if (intent.confidence < 0.8 && intent.type !== 'crisis') {
   175→      return getCurrentCharacterResult(currentCharacter, intent, studentProfile);
   176→    }
   177→  }
   178→
   179→  // 3. Route based on intent type
   180→  switch (intent.type) {
   181→    case 'crisis':
   182→      // Crisis: Buddy for peer support + adult referral
   183→      return {
   184→        characterType: 'buddy',
   185→        character: getBuddyForStudent(studentProfile),
   186→        intent,
   187→        reason: 'Crisis detected - peer support with built-in adult referral',
   188→      };
   189→
   190→    case 'academic_help':
   191→      // Academic: Maestro for the subject
   192→      if (intent.subject) {
   193→        const maestro = getMaestroForSubject(intent.subject);
   194→        if (maestro) {
   195→          return {
   196→            characterType: 'maestro',
   197→            character: maestro,
   198→            intent,
   199→            reason: `Subject expert for ${intent.subject}`,
   200→            alternatives: getAcademicAlternatives(intent, studentProfile),
   201→          };
   202→        }
   203→      }
   204→      // No subject detected, fallback to coach
   205→      return {
   206→        characterType: 'coach',
   207→        character: getCoachForStudent(studentProfile),
   208→        intent,
   209→        reason: 'Academic help needed but no specific subject - coach can help identify',
   210→      };
   211→
   212→    case 'method_help':
   213→      // Method/organization: Coach
   214→      return {
   215→        characterType: 'coach',
   216→        character: getCoachForStudent(studentProfile),
   217→        intent,
   218→        reason: 'Study method or organization help - coach specialty',
   219→        alternatives: intent.subject ? [{
   220→          character: getMaestroForSubject(intent.subject)!,
   221→          reason: 'Subject expert for specific content',
   222→        }].filter(a => a.character) : undefined,
   223→      };
   224→
   225→    case 'tool_request':
   226→      // Tool creation: Maestro if subject known, otherwise coach
   227→      if (intent.subject) {
   228→        const maestro = getMaestroForSubject(intent.subject);
   229→        if (maestro) {
   230→          return {
   231→            characterType: 'maestro',
   232→            character: maestro,
   233→            intent,
   234→            reason: 'Tool creation request - subject expert can create appropriate content',
   235→          };
   236→        }
   237→      }
   238→      return {
   239→        characterType: 'coach',
   240→        character: getCoachForStudent(studentProfile),
   241→        intent,
   242→        reason: 'Tool creation request - coach can help organize and create',
   243→      };
   244→
   245→    case 'emotional_support':
   246→      // Emotional: Buddy
   247→      return {
   248→        characterType: 'buddy',
   249→        character: getBuddyForStudent(studentProfile),
   250→        intent,
   251→        reason: 'Emotional support needed - peer can relate and validate',
   252→        alternatives: [{
   253→          character: getCoachForStudent(studentProfile),
   254→          reason: 'Coach for practical coping strategies',
   255→        }],
   256→      };
   257→
   258→    case 'tech_support':
   259→      // Tech support: Coach with knowledge base (Issue #16)
   260→      // Uses student's preferred coach, NOT a separate character
   261→      return {
   262→        characterType: 'coach',
   263→        character: getCoachForStudent(studentProfile),
   264→        intent,
   265→        reason: "Technical support with app - coach uses knowledge base",
   266→      };
   267→
   268→    case 'general_chat':
   269→    default:
   270→      // General: Coach as neutral starting point
   271→      return {
   272→        characterType: 'coach',
   273→        character: getCoachForStudent(studentProfile),
   274→        intent,
   275→        reason: 'General conversation - coach can help identify needs',
   276→      };
   277→  }
   278→}
   279→
   280→/**
   281→ * Gets the current character for continuity.
   282→ */
   283→function getCurrentCharacterResult(
   284→  current: { type: CharacterType; id: string },
   285→  intent: DetectedIntent,
   286→  profile: ExtendedStudentProfile
   287→): RoutingResult {
   288→  let character: MaestroFull | SupportTeacher | BuddyProfile | undefined;
   289→
   290→  switch (current.type) {
   291→    case 'maestro':
   292→      character = getMaestroById(current.id);
   293→      break;
   294→    case 'coach':
   295→      character = getSupportTeacherById(current.id as 'melissa' | 'roberto');
   296→      break;
   297→    case 'buddy':
   298→      character = getBuddyById(current.id as BuddyId);
   299→      break;
   300→  }
   301→
   302→  // Fallback if current character not found
   303→  if (!character) {
   304→    return routeToCharacter({ message: '', studentProfile: profile });
   305→  }
   306→
   307→  return {
   308→    characterType: current.type,
   309→    character,
   310→    intent,
   311→    reason: 'Continuing conversation with current character',
   312→  };
   313→}
   314→
   315→/**
   316→ * Gets alternative characters for academic help.
   317→ */
   318→function getAcademicAlternatives(
   319→  intent: DetectedIntent,
   320→  profile: ExtendedStudentProfile
   321→): Array<{ character: MaestroFull | SupportTeacher | BuddyProfile; reason: string }> {
   322→  const alternatives: Array<{ character: MaestroFull | SupportTeacher | BuddyProfile; reason: string }> = [];
   323→
   324→  // If emotional indicators, suggest buddy
   325→  if (intent.emotionalIndicators && intent.emotionalIndicators.length > 0) {
   326→    alternatives.push({
   327→      character: getBuddyForStudent(profile),
   328→      reason: 'Peer support for emotional aspects',
   329→    });
   330→  }
   331→
   332→  // Always suggest coach as backup
   333→  alternatives.push({
   334→    character: getCoachForStudent(profile),
   335→    reason: 'Study method support',
   336→  });
   337→
   338→  return alternatives;
   339→}
   340→
   341→// ============================================================================
   342→// CONVENIENCE FUNCTIONS
   343→// ============================================================================
   344→
   345→/**
   346→ * Quick route based on message only (uses default student profile).
   347→ * Useful for simple cases or testing.
   348→ */
   349→export function quickRoute(message: string): RoutingResult {
   350→  const defaultProfile: ExtendedStudentProfile = {
   351→    name: 'Student',
   352→    age: 14,
   353→    schoolYear: 2,
   354→    schoolLevel: 'superiore',
   355→    fontSize: 'medium',
   356→    highContrast: false,
   357→    dyslexiaFont: false,
   358→    voiceEnabled: false,
   359→    simplifiedLanguage: false,
   360→    adhdMode: false,
   361→    learningDifferences: [],
   362→  };
   363→
   364→  return routeToCharacter({
   365→    message,
   366→    studentProfile: defaultProfile,
   367→  });
   368→}
   369→
   370→/**
   371→ * Gets a greeting from the routed character.
   372→ */
   373→export function getCharacterGreeting(
   374→  result: RoutingResult,
   375→  studentProfile: ExtendedStudentProfile
   376→): string {
   377→  const { character, characterType } = result;
   378→
   379→  switch (characterType) {
   380→    case 'maestro':
   381→      return (character as MaestroFull).greeting;
   382→    case 'coach':
   383→      return (character as SupportTeacher).greeting;
   384→    case 'buddy':
   385→      return (character as BuddyProfile).getGreeting(studentProfile);
   386→    default:
   387→      return 'Ciao! Come posso aiutarti?';
   388→  }
   389→}
   390→
   391→/**
   392→ * Gets the system prompt for the routed character.
   393→ * SECURITY: All characters now have safety guardrails injected.
   394→ * Fix for Issue #30 - Maestri were previously deployed without safety.
   395→ */
   396→export function getCharacterSystemPrompt(
   397→  result: RoutingResult,
   398→  studentProfile: ExtendedStudentProfile
   399→): string {
   400→  const { character, characterType } = result;
   401→
   402→  switch (characterType) {
   403→    case 'maestro':
   404→      // CRITICAL FIX: Inject safety guardrails into Maestri prompts
   405→      // Previously, maestri were deployed WITHOUT safety - this fixes Issue #30
   406→      return injectSafetyGuardrails((character as MaestroFull).systemPrompt, {
   407→        role: 'maestro',
   408→        additionalNotes: `Sei ${(character as MaestroFull).name}, parla nel tuo stile storico.`,
   409→      });
   410→    case 'coach':
   411→      // Coach already has safety injected in support-teachers.ts
   412→      return (character as SupportTeacher).systemPrompt;
   413→    case 'buddy':
   414→      // Buddy already has safety injected in buddy-profiles.ts
   415→      return (character as BuddyProfile).getSystemPrompt(studentProfile);
   416→    default:
   417→      return '';
   418→  }
   419→}
   420→
   421→/**
   422→ * Suggests a character switch based on conversation flow.
   423→ * Call this when the current character detects a need for different support.
   424→ */
   425→export function suggestCharacterSwitch(
   426→  currentType: CharacterType,
   427→  suggestedType: CharacterType,
   428→  profile: ExtendedStudentProfile,
   429→  reason: string
   430→): { character: SupportCharacter | MaestroFull; message: string } {
   431→  let character: SupportCharacter | MaestroFull;
   432→  let message: string;
   433→
   434→  switch (suggestedType) {
   435→    case 'maestro':
   436→      // This would need a subject - defaulting to math for now
   437→      character = getMaestroForSubject('mathematics')!;
   438→      message = `${reason} Vuoi parlare con un Professore?`;
   439→      break;
   440→    case 'coach':
   441→      character = getCoachForStudent(profile);
   442→      message = `${reason} ${(character as SupportTeacher).name} può aiutarti!`;
   443→      break;
   444→    case 'buddy':
   445→      character = getBuddyForStudent(profile);
   446→      message = `${reason} ${(character as BuddyProfile).name} ti capisce!`;
   447→      break;
   448→    default:
   449→      character = getCoachForStudent(profile);
   450→      message = reason;
   451→  }
   452→
   453→  return { character, message };
   454→}
