   367→                      </div>
   368→                    </button>
   369→                  </div>
   370→                </motion.div>
   371→              )}
   372→            </AnimatePresence>
   373→          </div>
   374→
   375→          {/* Footer with back button */}
   376→          {step !== 'subject' && (
   377→            <div className="p-4 border-t border-slate-200 dark:border-slate-700">
   378→              <Button variant="outline" onClick={handleBack} className="w-full">
   379→                <ArrowLeft className="mr-2 h-4 w-4" />
   380→                Indietro
   381→              </Button>
   382→            </div>
   383→          )}
   384→        </motion.div>
   385→      </motion.div>
   386→    </AnimatePresence>
   387→  );
   388→}
