   130→
   131→export function CharacterChatView({ characterId, characterType }: CharacterChatViewProps) {
   132→  const [messages, setMessages] = useState<Message[]>([]);
   133→  const [input, setInput] = useState('');
   134→  const [isLoading, setIsLoading] = useState(false);
   135→  const [isVoiceActive, setIsVoiceActive] = useState(false);
   136→  const [connectionInfo, setConnectionInfo] = useState<VoiceConnectionInfo | null>(null);
   137→  const [configError, setConfigError] = useState<string | null>(null);
   138→  const [activeTool, setActiveTool] = useState<ToolState | null>(null);
   139→  const [isToolMinimized, setIsToolMinimized] = useState(false);
   140→  const messagesEndRef = useRef<HTMLDivElement>(null);
   141→  const inputRef = useRef<HTMLTextAreaElement>(null);
   142→  const hasAttemptedConnection = useRef(false);
   143→  const lastTranscriptIdRef = useRef<string | null>(null);
   144→  const conversationIdRef = useRef<string | null>(null);
   145→  const hasLoadedMessages = useRef(false);
   146→
   147→  // Conversation persistence
   148→  const { conversations, createConversation, addMessage: addMessageToStore } = useConversationStore();
   149→
   150→  const character = getCharacterInfo(characterId, characterType);
   151→
   152→  // Voice session with transcript callback that syncs to messages
   153→  const voiceSession = useVoiceSession({
   154→    onError: (error) => {
   155→      const message = error instanceof Error ? error.message : String(error);
   156→      logger.error('Voice call error', { message });
   157→      setConfigError(message || 'Errore di connessione vocale');
   158→    },
   159→    onTranscript: (role, text) => {
   160→      // Add voice transcripts to the chat messages
   161→      const transcriptId = `voice-${role}-${Date.now()}`;
   162→
   163→      // Avoid duplicate transcripts
   164→      if (lastTranscriptIdRef.current === text.substring(0, 50)) {
   165→        return;
   166→      }
   167→      lastTranscriptIdRef.current = text.substring(0, 50);
   168→
   169→      setMessages(prev => [...prev, {
   170→        id: transcriptId,
   171→        role: role as 'user' | 'assistant',
   172→        content: text,
   173→        timestamp: new Date(),
   174→        isVoice: true,
   175→      }]);
   176→    },
   177→  });
   178→
   179→  // Destructure voice session
   180→  const {
   181→    isConnected,
   182→    isListening,
   183→    isSpeaking,
   184→    isMuted,
   185→    inputLevel,
   186→    connectionState,
   187→    connect,
   188→    disconnect,
   189→    toggleMute,
   190→    sessionId: voiceSessionId,
   191→  } = voiceSession;
   192→
   193→  // Fetch voice connection info
   194→  useEffect(() => {
   195→    async function fetchConnectionInfo() {
   196→      try {
   197→        const response = await fetch('/api/realtime/token');
   198→        const data = await response.json();
   199→        if (data.error) {
   200→          logger.error('Voice API error', { error: data.error });
   201→          setConfigError(data.message || 'Servizio vocale non configurato');
   202→          return;
   203→        }
   204→        setConnectionInfo(data as VoiceConnectionInfo);
   205→      } catch (error) {
   206→        logger.error('Failed to get voice connection info', { error: String(error) });
   207→        setConfigError('Impossibile connettersi al servizio vocale');
   208→      }
   209→    }
   210→    fetchConnectionInfo();
   211→  }, []);
   212→
   213→  // Connect when voice is activated
   214→  useEffect(() => {
   215→    const startConnection = async () => {
   216→      if (!isVoiceActive || hasAttemptedConnection.current) return;
   217→      if (!connectionInfo || isConnected || connectionState !== 'idle') return;
   218→
   219→      hasAttemptedConnection.current = true;
   220→      setConfigError(null);
   221→
   222→      try {
   223→        const maestroLike = characterToMaestro(character, characterId);
   224→        await connect(maestroLike, connectionInfo);
   225→      } catch (error) {
   226→        logger.error('Voice connection failed', { error: String(error) });
   227→        if (error instanceof DOMException && error.name === 'NotAllowedError') {
   228→          setConfigError('Microfono non autorizzato. Abilita il microfono nelle impostazioni del browser.');
   229→        } else {
   230→          setConfigError('Errore di connessione vocale');
   231→        }
   232→      }
   233→    };
   234→
   235→    startConnection();
   236→  }, [isVoiceActive, connectionInfo, isConnected, connectionState, character, characterId, connect]);
   237→
   238→  // Reset connection attempt flag when voice is deactivated
   239→  useEffect(() => {
   240→    if (!isVoiceActive) {
   241→      hasAttemptedConnection.current = false;
   242→    }
   243→  }, [isVoiceActive]);
   244→
   245→  // Handle voice call toggle
   246→  const handleVoiceCall = useCallback(() => {
   247→    if (isVoiceActive) {
   248→      disconnect();
   249→    }
   250→    setIsVoiceActive(prev => !prev);
   251→  }, [isVoiceActive, disconnect]);
   252→
   253→  // Scroll to bottom when messages change
   254→  useEffect(() => {
   255→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
   256→  }, [messages]);
   257→
   258→  // Load or create conversation on mount
   259→  useEffect(() => {
   260→    if (hasLoadedMessages.current) return;
   261→    hasLoadedMessages.current = true;
   262→
   263→    async function initConversation() {
   264→      // Find existing conversation for this character
   265→      const existingConv = conversations.find(c => c.maestroId === characterId);
   266→
   267→      if (existingConv && existingConv.messages.length > 0) {
   268→        // Load existing messages
   269→        conversationIdRef.current = existingConv.id;
   270→        setMessages(existingConv.messages.map(m => ({
   271→          id: m.id,
   272→          role: m.role as 'user' | 'assistant',
   273→          content: m.content,
   274→          timestamp: new Date(m.timestamp),
   275→        })));
   276→        logger.debug('Loaded existing conversation', { characterId, messageCount: existingConv.messages.length });
   277→      } else {
   278→        // Create new conversation
   279→        const newConvId = await createConversation(characterId);
   280→        conversationIdRef.current = newConvId;
   281→
   282→        // Add greeting
   283→        const greetingMessage = {
   284→          id: 'greeting',
   285→          role: 'assistant' as const,
   286→          content: character.greeting,
   287→          timestamp: new Date(),
   288→        };
   289→        setMessages([greetingMessage]);
   290→
   291→        // Persist greeting
   292→        await addMessageToStore(newConvId, {
   293→          role: 'assistant',
   294→          content: character.greeting,
   295→        });
   296→        logger.debug('Created new conversation', { characterId, convId: newConvId });
   297→      }
   298→    }
   299→
   300→    initConversation();
   301→  }, [characterId, character.greeting, conversations, createConversation, addMessageToStore]);
   302→
   303→  const handleSend = useCallback(async () => {
   304→    if (!input.trim() || isLoading) return;
   305→
   306→    const userMessage: Message = {
   307→      id: `user-${Date.now()}`,
   308→      role: 'user',
   309→      content: input.trim(),
   310→      timestamp: new Date(),
   311→    };
   312→
   313→    setMessages(prev => [...prev, userMessage]);
   314→    setInput('');
   315→    setIsLoading(true);
   316→
   317→    // Persist user message
   318→    if (conversationIdRef.current) {
   319→      addMessageToStore(conversationIdRef.current, {
   320→        role: 'user',
   321→        content: userMessage.content,
   322→      });
   323→    }
   324→
   325→    try {
   326→      const response = await fetch('/api/chat', {
   327→        method: 'POST',
   328→        headers: { 'Content-Type': 'application/json' },
   329→        body: JSON.stringify({
   330→          messages: [
   331→            ...messages.map(m => ({ role: m.role, content: m.content })),
   332→            { role: 'user', content: userMessage.content },
   333→          ],
   334→          systemPrompt: character.systemPrompt,
   335→          maestroId: characterId,
   336→          enableTools: true,
   337→        }),
   338→      });
   339→
   340→      if (!response.ok) throw new Error('Failed to send message');
   341→
   342→      const data = await response.json();
   343→
   344→      // ADR 0020: Generate contextual fallback if AI made tool calls but no content
   345→      let responseContent = data.content || data.message;
   346→      if (!responseContent || responseContent.trim() === '') {
   347→        if (data.toolCalls && data.toolCalls.length > 0) {
   348→          const toolNames = data.toolCalls.map((tc: { type?: string }) => tc.type);
   349→          if (toolNames.includes('create_mindmap')) {
   350→            responseContent = 'Ti sto creando la mappa mentale...';
   351→          } else if (toolNames.includes('create_quiz')) {
   352→            responseContent = 'Ti sto preparando il quiz...';
   353→          } else if (toolNames.includes('create_flashcards')) {
   354→            responseContent = 'Ti sto creando le flashcard...';
   355→          } else if (toolNames.includes('create_summary')) {
   356→            responseContent = 'Ti sto preparando il riassunto...';
   357→          } else {
   358→            responseContent = 'Sto elaborando la tua richiesta...';
   359→          }
   360→        } else {
   361→          responseContent = 'Mi dispiace, non ho capito. Puoi ripetere?';
   362→        }
   363→      }
   364→
   365→      const assistantMessage: Message = {
   366→        id: `assistant-${Date.now()}`,
   367→        role: 'assistant',
   368→        content: responseContent,
   369→        timestamp: new Date(),
   370→      };
   371→
   372→      setMessages(prev => [...prev, assistantMessage]);
   373→
   374→      // Persist assistant message
   375→      if (conversationIdRef.current) {
   376→        addMessageToStore(conversationIdRef.current, {
   377→          role: 'assistant',
   378→          content: assistantMessage.content,
   379→        });
   380→      }
   381→
   382→      // Handle tool calls if any - update activeTool state
   383→      if (data.toolCalls && data.toolCalls.length > 0) {
   384→        const toolCall = data.toolCalls[0];
   385→        // Map function name (create_quiz) to tool type (quiz)
   386→        const toolType = FUNCTION_NAME_TO_TOOL_TYPE[toolCall.type] || toolCall.type as ToolType;
   387→        // Extract actual data from result object
   388→        const toolContent = toolCall.result?.data || toolCall.result || toolCall.arguments;
   389→        setActiveTool({
   390→          id: toolCall.id,
   391→          type: toolType,
   392→          status: 'completed',
   393→          progress: 1,
   394→          content: toolContent,
   395→          createdAt: new Date(),
   396→        });
   397→      }
   398→    } catch (error) {
   399→      logger.error('Chat error', { error });
   400→      setMessages(prev => [...prev, {
   401→        id: `error-${Date.now()}`,
   402→        role: 'assistant',
   403→        content: 'Mi dispiace, c\'è stato un errore. Riprova tra poco!',
   404→        timestamp: new Date(),
   405→      }]);
   406→    } finally {
   407→      setIsLoading(false);
   408→    }
   409→  }, [input, isLoading, messages, character.systemPrompt, characterId, addMessageToStore]);
   410→
   411→  const handleKeyDown = (e: React.KeyboardEvent) => {
   412→    if (e.key === 'Enter' && !e.shiftKey) {
   413→      e.preventDefault();
   414→      handleSend();
   415→    }
   416→  };
   417→
   418→  // Handle tool button requests (like maestro chat)
   419→  const handleToolRequest = useCallback(async (toolType: ToolType) => {
   420→    if (isLoading) return;
   421→
   422→    setIsLoading(true);
   423→
   424→    // Create initial tool state
   425→    const newTool: ToolState = {
   426→      id: `tool-${Date.now()}`,
   427→      type: toolType,
   428→      status: 'initializing',
   429→      progress: 0,
   430→      content: null,
   431→      createdAt: new Date(),
   432→    };
   433→    setActiveTool(newTool);
   434→
   435→    // Build the request message based on tool type
   436→    const toolPrompts: Partial<Record<ToolType, string>> = {
   437→      mindmap: 'Crea una mappa mentale sull\'argomento che stiamo studiando',
   438→      quiz: 'Fammi un quiz per verificare cosa ho capito',
   439→      flashcard: 'Crea delle flashcard per aiutarmi a memorizzare',
   440→      demo: 'Mostrami una demo interattiva',
   441→      summary: 'Fammi un riassunto strutturato',
   442→      diagram: 'Crea un diagramma',
   443→      timeline: 'Crea una linea del tempo',
   444→    };
   445→
   446→    const userMessage: Message = {
   447→      id: `user-${Date.now()}`,
   448→      role: 'user',
   449→      content: toolPrompts[toolType] || `Usa lo strumento ${toolType}`,
   450→      timestamp: new Date(),
   451→    };
   452→
   453→    setMessages(prev => [...prev, userMessage]);
   454→
   455→    try {
   456→      const response = await fetch('/api/chat', {
   457→        method: 'POST',
   458→        headers: { 'Content-Type': 'application/json' },
   459→        body: JSON.stringify({
   460→          messages: [
   461→            ...messages.map(m => ({ role: m.role, content: m.content })),
   462→            { role: 'user', content: userMessage.content },
   463→          ],
   464→          systemPrompt: character.systemPrompt,
   465→          maestroId: characterId,
   466→          enableTools: true,
   467→          requestedTool: toolType === 'flashcard' ? 'flashcard' : toolType,
   468→        }),
   469→      });
   470→
   471→      if (!response.ok) throw new Error('Failed to request tool');
   472→
   473→      const data = await response.json();
   474→
   475→      const assistantMessage: Message = {
   476→        id: `assistant-${Date.now()}`,
   477→        role: 'assistant',
   478→        content: data.content || '',
   479→        timestamp: new Date(),
   480→      };
   481→
   482→      if (data.content) {
   483→        setMessages(prev => [...prev, assistantMessage]);
   484→      }
   485→
   486→      // Update tool state based on response
   487→      if (data.toolCalls?.length > 0) {
   488→        const toolCall = data.toolCalls[0];
   489→        // Map function name (create_quiz) to tool type (quiz)
   490→        const mappedToolType = FUNCTION_NAME_TO_TOOL_TYPE[toolCall.type] || toolType;
   491→        // Extract actual data from result object
   492→        const toolContent = toolCall.result?.data || toolCall.result || toolCall.arguments;
   493→        setActiveTool({
   494→          ...newTool,
   495→          type: mappedToolType,
   496→          status: 'completed',
   497→          progress: 1,
   498→          content: toolContent,
   499→        });
   500→      } else {
   501→        // No tool was created, clear the state
   502→        setActiveTool(null);
   503→      }
   504→    } catch (error) {
   505→      logger.error('Tool request error', { error });
   506→      setMessages(prev => [...prev, {
   507→        id: `error-${Date.now()}`,
   508→        role: 'assistant',
   509→        content: 'Mi dispiace, non sono riuscito a creare lo strumento. Riprova?',
   510→        timestamp: new Date(),
   511→      }]);
   512→      setActiveTool({
   513→        ...newTool,
   514→        status: 'error',
   515→        error: 'Errore nella creazione dello strumento',
   516→      });
   517→    } finally {
   518→      setIsLoading(false);
   519→    }
   520→  }, [isLoading, messages, character.systemPrompt, characterId]);
   521→
   522→  // Check if tool is active for layout
   523→  const hasActiveTool = activeTool && activeTool.status !== 'error';
   524→
   525→  return (
   526→    <div className="flex gap-4 h-[calc(100vh-8rem)]">
   527→      {/* Main Chat Area */}
   528→      <div className="flex-1 flex flex-col min-w-0">
