   612→                      {character.name.charAt(0)}
   613→                    </div>
   614→                  )}
   615→                </div>
   616→              )}
   617→              <div
   618→                className={cn(
   619→                  'max-w-[75%] rounded-2xl px-4 py-3',
   620→                  message.role === 'user'
   621→                    ? 'bg-accent-themed text-white rounded-br-md'
   622→                    : 'bg-white dark:bg-slate-800 text-slate-900 dark:text-slate-100 rounded-bl-md shadow-sm'
   623→                )}
   624→              >
