   648→                    width={36}
   649→                    height={36}
   650→                    className="rounded-full object-cover"
   651→                  />
   652→                ) : (
   653→                  <div className="w-9 h-9 rounded-full bg-gradient-to-br from-purple-500 to-pink-500 flex items-center justify-center text-white text-sm font-bold">
   654→                    {character.name.charAt(0)}
   655→                  </div>
   656→                )}
   657→              </div>
   658→              <div className="bg-white dark:bg-slate-800 rounded-2xl rounded-bl-md px-4 py-3 shadow-sm">
   659→                <div className="flex gap-1">
   660→                  <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
   661→                  <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
   662→                  <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
   663→                </div>
   664→              </div>
   665→            </motion.div>
   666→          )}
   667→
   668→          <div ref={messagesEndRef} />
   669→        </div>
   670→
   671→        {/* Input Area */}
   672→        <div className="p-4 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 rounded-b-2xl">
   673→          {/* Tool Buttons - only for coaches */}
   674→          {characterType === 'coach' && (
   675→            <ToolButtons
   676→              onToolRequest={handleToolRequest}
   677→              disabled={isLoading}
