   688→              className="flex-1 resize-none rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-accent-themed"
   689→              rows={1}
   690→              disabled={isLoading}
   691→            />
   692→            <Button
   693→              onClick={handleSend}
   694→              disabled={!input.trim() || isLoading}
   695→              className="bg-accent-themed hover:bg-accent-themed/90"
   696→            >
   697→              {isLoading ? (
   698→                <Loader2 className="h-5 w-5 animate-spin" />
   699→              ) : (
   700→                <Send className="h-5 w-5" />
