   707→      {/* Tool Panel - shown when tool is active */}
   708→      {hasActiveTool && (
   709→        <div className="w-[400px] h-full flex-shrink-0 overflow-hidden rounded-xl border border-slate-200 dark:border-slate-700">
   710→          <ToolPanel
   711→            tool={activeTool}
   712→            maestro={{
   713→              name: character.name,
   714→              avatar: character.avatar || '/avatars/default.jpg',
   715→              color: character.themeColor,
