          .map(([maestroId, data]) => {
            let priority: 'high' | 'medium' | 'low' = 'low';
            let reason = '';

            if (data.nearestDays <= 1) {
              priority = 'high';
              reason = data.types.has('exam') || data.types.has('test')
                ? 'Test tomorrow - review now!'
                : 'Event tomorrow';
            } else if (data.nearestDays <= 3) {
              priority = 'high';
              reason = `${data.count} event${data.count > 1 ? 's' : ''} in ${data.nearestDays} days`;
            } else if (data.nearestDays <= 5) {
              priority = 'medium';
              reason = `Prepare for upcoming ${Array.from(data.types).join('/')}`;
            } else {
              priority = 'low';
              reason = `${data.count} event${data.count > 1 ? 's' : ''} this week`;
            }

            return { maestroId, reason, priority };
          })
          .sort((a, b) => {
            const priorityOrder = { high: 0, medium: 1, low: 2 };
            return priorityOrder[a.priority] - priorityOrder[b.priority];
          });
      },
    })
);

// === UI STORE ===

interface UIState {
  sidebarOpen: boolean;
  settingsOpen: boolean;
  currentView: 'maestri' | 'chat' | 'voice' | 'quiz' | 'flashcards' | 'homework' | 'progress';
  // Focus Mode - fullscreen tool view
  focusMode: boolean;
  focusTool: ToolState | null;
  focusToolType: ToolType | null;
  focusMaestroId: string | null;
  focusInteractionMode: 'voice' | 'chat';
  // Actions
  toggleSidebar: () => void;
  setSidebarOpen: (open: boolean) => void;
  toggleSettings: () => void;
  setCurrentView: (view: UIState['currentView']) => void;
  // Focus Mode Actions
  enterFocusMode: (toolType: ToolType, maestroId?: string, interactionMode?: 'voice' | 'chat') => void;
  setFocusTool: (tool: ToolState | null) => void;
  exitFocusMode: () => void;
}

export const useUIStore = create<UIState>((set) => ({
  sidebarOpen: true,
  settingsOpen: false,
  currentView: 'maestri',
  focusMode: false,
  focusTool: null,
  focusToolType: null,
  focusMaestroId: null,
  focusInteractionMode: 'chat',
  toggleSidebar: () => set((state) => ({ sidebarOpen: !state.sidebarOpen })),
  setSidebarOpen: (sidebarOpen) => set({ sidebarOpen }),
  toggleSettings: () => set((state) => ({ settingsOpen: !state.settingsOpen })),
  setCurrentView: (currentView) => set({ currentView }),
  enterFocusMode: (toolType, maestroId, interactionMode = 'chat') => set({
    focusMode: true,
    focusToolType: toolType,
    focusMaestroId: maestroId || null,
    focusInteractionMode: interactionMode,
    focusTool: null, // Will be set when tool is created
  }),
  setFocusTool: (tool) => set({ focusTool: tool }),
  exitFocusMode: () => set({
    focusMode: false,
    focusTool: null,
    focusToolType: null,
    focusMaestroId: null,
    focusInteractionMode: 'chat',
  }),
}));

// === SYNC HOOK ===

export async function initializeStores() {
  // Ensure user exists (creates cookie if needed)
  await fetch('/api/user');

  // Load data from server
  await Promise.all([
    useSettingsStore.getState().loadFromServer(),
    useProgressStore.getState().loadFromServer(),
    useConversationStore.getState().loadFromServer(),
    useLearningsStore.getState().loadFromServer(),
  ]);
}

export function setupAutoSync(intervalMs = 30000) {
  // Auto-sync every 30 seconds if there are pending changes
  return setInterval(async () => {
    const settings = useSettingsStore.getState();
    const progress = useProgressStore.getState();

    if (settings.pendingSync) {
      await settings.syncToServer();
    }
    if (progress.pendingSync) {
      await progress.syncToServer();
    }
  }, intervalMs);
}

